// ===============================================
//     НОДА: ОДИН ITEM НА ОДНУ СТРОКУ
// ===============================================

// Получаем конфигурацию из предыдущей ноды
const config = $('config').first().json.config;
const request_counter = $('GetRequestCounter').first().json['Текущее значение']
let currentCounter = request_counter;

const existing_ids = $('GetLayoutsIDExisting').all().map(item => item.json.ID)

// Получаем данные из Google Sheets (лист "Реестр заявок")  
const registryData = $('checkTable').all();


function getRowNumber(rowObj, idx) {
  return rowObj.row_number || rowObj._rowNumber || rowObj.rowNumber || (idx + 2);
}

// Массив результатов - один item на строку
const results = [];

// Обрабатываем каждую строку
registryData.forEach((item, index) => {

  try {
    const row = item.json;
    const rowNumber = getRowNumber(row, index);
    const C = config.COLUMNS;

    // Проверка обязательных полей
    const missing = [];
    for (const field of config.REQUIRED_FIELDS.base) {
      const value = row[field];
      if (value === undefined || value === null || String(value).trim() === '') {
        missing.push(field);
      }
    }

    // Дополнительная проверка для квалификации
    const scenario = row[C.REGISTRY.SCENARIO];
    if (scenario === 'Диплом с квалификацией') {
      const qualification = row[C.REGISTRY.QUALIFICATION];
      if (!qualification || String(qualification).trim() === '') {
        missing.push(C.REGISTRY.QUALIFICATION);
      }
    }

    // Проверка допустимых часов
    const hours = parseInt(row[C.REGISTRY.HOURS]);
    if (!isNaN(hours) && !config.VALID_HOURS.includes(hours)) {
      missing.push(`${C.REGISTRY.HOURS} (недопустимое значение: ${hours})`);
    }

  if (missing.length === 0) {
    // 👇 ДОБАВИТЬ ЭТУ ПРОВЕРКУ СЮДА
    const existingId = row[C.REGISTRY.ID]; // или как называется колонка ID в конфиге

    if (!existingId || String(existingId).trim() === '') {
      // ✅ ID нет → генерируем новый
      let newId;
      do {
        currentCounter += 1;
        newId = `REQ-${String(currentCounter).padStart(5, '0')}`;
      } while (existing_ids.includes(newId));

      const fullName = row[C.FULL_NAME] || 'Не указано';

      results.push({
        json: {
          rowNumber,
          action: 'assign_id',
          newId,
          fullName,
          scenario,

          registryUpdates: {
            [C.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU', {
              timeZone: 'Europe/Moscow',
              year: 'numeric',
              month: '2-digit', 
              day: '2-digit',
              hour: '2-digit',
              minute: '2-digit'
            })
          }
        }
      });

    } else {
      // ✅ ID уже есть → пропускаем
      const fullName = row[C.FULL_NAME] || 'Не указано';

      results.push({
        json: {
          rowNumber,
          action: 'exist_id', // новое действие
          existingId,
          fullName,
          scenario,

          registryUpdates: {
            [C.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU', {
              timeZone: 'Europe/Moscow',
              year: 'numeric',
              month: '2-digit', 
              day: '2-digit',
              hour: '2-digit',
              minute: '2-digit'
            })
          }
        }
      });
    }
    } else {
      // ❌ Неполные данные - ОДИН ITEM НА СТРОКУ
      const fullName = row[C.FULL_NAME] || 'Не указано';

      results.push({
        json: {
          // Основная информация о строке
          rowNumber,
          action: 'incomplete',
          fullName,
          missingFields: missing,

          // Обновления для реестра
          registryUpdates: {
            [C.REGISTRY.LAST_UPDATE]: new Date().toLocaleString('ru-RU', {
              timeZone: 'Europe/Moscow',
              year: 'numeric',
              month: '2-digit', 
              day: '2-digit',
              hour: '2-digit',
              minute: '2-digit'
            })
          }
        }
      });
    }

  } catch (err) {
    // Ошибка обработки строки
    results.push({
      json: {
        rowNumber: index + 2,
        action: 'error',
        error: err.message
      }
    });
  }
});

console.log(`Обработано: ${results.length} строк`);
const assigned = results.filter(r => r.json.action === 'assign_id').length;
const incomplete = results.filter(r => r.json.action === 'incomplete').length;
console.log(results)

console.log(`- Присвоено ID: ${assigned}`);
console.log(`- Неполные данные: ${incomplete}`);

results.push({
  json: {
    counterUpdate: currentCounter
  }
});

return results;

