const doc = $input.first().json;

const content = doc.body.content;
const table = content
  .find(el => el.table && el.table.columns === 9)?.table;

if (!table) throw new Error("Таблица не найдена");

const updates = [];
for (let i = table.tableRows.length - 1; i >= 1; i--) {
  const cell = table.tableRows[i].tableCells[0];
  const textRun = cell.content[0].paragraph.elements
    .find(el => el.textRun && el.textRun.content !== "\n");

  const newText = String(i);

  if (textRun) {
    updates.push({
      startIndex: textRun.startIndex,
      endIndex: textRun.endIndex - 1, // убираем \n из диапазона
      text: newText,
      hasContent: true
    });
  } else {
    const insertIndex = cell.content[0].paragraph.elements[0].startIndex;
    updates.push({
      startIndex: insertIndex,
      endIndex: null,
      text: newText,
      hasContent: false
    });
  }
}

const requests = updates.flatMap(({ startIndex, endIndex, text, hasContent }) => {
  const ops = [];
  if (hasContent) {
    ops.push({
      deleteContentRange: {
        range: { startIndex, endIndex }
      }
    });
  }
  ops.push({
    insertText: {
      location: { index: startIndex },
      text
    }
  });
  return ops;
});

return [{ json: { requests } }];

const doc = $input.first().json;
const body = doc.body;
const documentId = doc.documentId;

const SCALE = 0.75;
const MIN_SIZE = 5;
const MIN_LENGTH = 230;

const START_MARKER = 'Решением аттестационной комиссии';
const END_MARKER = 'Основание:';

const requests = [];

function findLastMarkerIndex(content, marker) {
  for (const element of content || []) {
    if (element.table) {
      for (const row of element.table.tableRows || []) {
        for (const cell of row.tableCells || []) {
          const result = findLastMarkerIndex(cell.content, marker);
          if (result) return result;
        }
      }
    }
    if (element.paragraph) {
      const fullText = element.paragraph.elements
        .map(pe => pe.textRun?.content || '')
        .join('');
      if (fullText.includes(marker)) {
        const elements = element.paragraph.elements;
        const lastEl = elements[elements.length - 1];
        return {
          startIndex: elements[0].startIndex,
          endIndex: lastEl.endIndex
        };
      }
    }
  }
  return null;
}

function getAllText(content, rangeStart, rangeEnd) {
  let text = '';
  for (const element of content || []) {
    if (element.table) {
      for (const row of element.table.tableRows || []) {
        for (const cell of row.tableCells || []) {
          text += getAllText(cell.content, rangeStart, rangeEnd);
        }
      }
    }
    if (element.paragraph) {
      for (const pe of element.paragraph.elements || []) {
        if (!pe.textRun) continue;
        if (pe.startIndex >= rangeStart && pe.endIndex <= rangeEnd) {
          text += pe.textRun.content || '';
        }
      }
    }
  }
  return text;
}

function processContent(content, rangeStart, rangeEnd) {
  for (const element of content || []) {
    if (element.table) {
      for (const row of element.table.tableRows || []) {
        for (const cell of row.tableCells || []) {
          processContent(cell.content, rangeStart, rangeEnd);
        }
      }
    }
    if (element.paragraph) {
      for (const pe of element.paragraph.elements || []) {
        if (!pe.textRun) continue;
        const currentSize = pe.textRun.textStyle?.fontSize?.magnitude;
        if (!currentSize) continue;
        if (pe.startIndex >= rangeStart && pe.endIndex <= rangeEnd) {
          const newSize = Math.max(Math.round(currentSize * SCALE), MIN_SIZE);
          requests.push({
            updateTextStyle: {
              range: {
                startIndex: pe.startIndex,
                endIndex: pe.endIndex
              },
              textStyle: {
                fontSize: {
                  magnitude: newSize,
                  unit: 'PT'
                }
              },
              fields: 'fontSize'
            }
          });
        }
      }
    }
  }
}

const startEl = findLastMarkerIndex(body.content, START_MARKER);
const endEl = findLastMarkerIndex(body.content, END_MARKER);

if (!startEl || !endEl) {
  throw new Error('Маркеры не найдены в документе');
}

const rangeText = getAllText(body.content, startEl.endIndex, endEl.startIndex);

if (rangeText.trim().replace(/\n/g, '').length >= MIN_LENGTH) {
  processContent(body.content, startEl.endIndex, endEl.startIndex);
}

return [{
  json: {
    documentId,
    requests
  }
}];

const doc = $input.first().json;
const body = doc.body;
const documentId = doc.documentId;

const SCALE = 0.85;
const MIN_SIZE = 5;
const MIN_LENGTH = 160;
const MARKER = 'Протокол';

const requests = [];

function getCellText(cellContent) {
  let text = '';
  for (const element of cellContent || []) {
    if (element.table) {
      for (const row of element.table.tableRows || []) {
        for (const cell of row.tableCells || []) {
          text += getCellText(cell.content);
        }
      }
    }
    if (element.paragraph) {
      for (const pe of element.paragraph.elements || []) {
        text += pe.textRun?.content || '';
      }
    }
  }
  return text;
}

function processCell(cellContent) {
  let markerStartIndex = null;

  for (const element of cellContent || []) {
    if (element.paragraph) {
      const fullText = element.paragraph.elements
        .map(pe => pe.textRun?.content || '')
        .join('');
      if (fullText.includes(MARKER)) {
        markerStartIndex = element.paragraph.elements[0].startIndex;
        break;
      }
    }
  }

  if (markerStartIndex === null) return;

  let rangeText = '';
  for (const element of cellContent || []) {
    if (element.paragraph) {
      for (const pe of element.paragraph.elements || []) {
        if (!pe.textRun) continue;
        if (pe.endIndex <= markerStartIndex) {
          rangeText += pe.textRun.content || '';
        }
      }
    }
  }

  const textLength = rangeText.replace(/\s/g, '').length;
  if (textLength < MIN_LENGTH) return;

  for (const element of cellContent || []) {
    if (element.paragraph) {
      for (const pe of element.paragraph.elements || []) {
        if (!pe.textRun) continue;
        const currentSize = pe.textRun.textStyle?.fontSize?.magnitude;
        if (!currentSize) continue;
        if (pe.endIndex <= markerStartIndex) {
          const newSize = Math.max(Math.round(currentSize * SCALE), MIN_SIZE);
          requests.push({
            updateTextStyle: {
              range: {
                startIndex: pe.startIndex,
                endIndex: pe.endIndex
              },
              textStyle: {
                fontSize: { magnitude: newSize, unit: 'PT' }
              },
              fields: 'fontSize'
            }
          });
        }
      }
    }
  }
}

function traverseContent(content) {
  for (const element of content || []) {
    if (element.table) {
      for (const row of element.table.tableRows || []) {
        for (const cell of row.tableCells || []) {
          const cellText = getCellText(cell.content);
          if (cellText.includes(MARKER)) {
            processCell(cell.content);
          } else {
            traverseContent(cell.content);
          }
        }
      }
    }
  }
}

traverseContent(body.content);

if (requests.length === 0) {
  return [{ json: { documentId, requests: [] } }];
}

return [{
  json: {
    documentId,
    requests
  }
}];

