function splitFIO(fullName) {
  const parts = (fullName || "").trim().split(/\s+/);
  return {
    surname:    parts[0] || "",
    name:       parts[1] || "",
    patronymic: parts.slice(2).join(" ") || ""
  };
}

function parseGroups(value) {
  if (!value || String(value).trim() === "") return [];
  return String(value).split(",").map(s => s.trim()).filter(Boolean);
}

// Парсит строку вида "А1:0101,Б:0202" → Map { "А1" => "0101", "Б" => "0202" }
function parseRegNumbers(value) {
  const result = new Map();
  if (!value || String(value).trim() === "") return result;
  String(value).split(",").forEach(pair => {
    const idx = pair.indexOf(":");
    if (idx === -1) return;
    const key = pair.slice(0, idx).trim();
    const val = pair.slice(idx + 1).trim();
    if (key && val) result.set(key, val);
  });
  return result;
}

// ===============================================
//     ГЕНЕРАЦИЯ РЕГ-НОМЕРА
// Счётчики мутируются в памяти — корректная
// последовательность внутри одного прогона
// ===============================================

function generateRegNumber(counterName) {
  const format = Object.values(config.REG_NUMBER_FORMATS)
    .find(f => f.counter_name === counterName);

  if (!format) {
    console.warn(`  ⚠️ Формат для счётчика "${counterName}" не найден`);
    return "";
  }

  const counter = countersData.find(c =>
    c.json[CC.COUNTER_TYPE] === counterName
  );

  let current = counter
    ? (parseInt(counter.json[CC.CURRENT_VALUE]) || 0)
    : 0;

  current += 1;

  // Мутируем в памяти сразу — до любых return
  if (counter) counter.json[CC.CURRENT_VALUE] = current;

  const now   = new Date();
  const month = String(now.getMonth() + 1).padStart(2, "0");
  const yy    = String(now.getFullYear()).slice(-2);

  const regNumber = format.format
    .replace("{number}", current)
    .replace("{month}",  month)
    .replace("{yy}",     yy)
    .replace("{prefix}", format.prefix || "");

  console.log(`  🔢 Счётчик "${counterName}": ${current} → рег. "${regNumber}"`);
  return regNumber;
}

// ===============================================
//     РАСЧЁТ ПЕРИОДА ОБУЧЕНИЯ
// ===============================================

function calculateStudyPeriod(regData, hours) {
  function isValidDate(d) { return d instanceof Date && !isNaN(d.getTime()); }

  function parseDate(v) {
    if (!v) return null;
    if (typeof v === "string") {
      const m = v.match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
      if (m) {
        const d = new Date(+m[3], +m[2] - 1, +m[1]);
        return isValidDate(d) ? d : null;
      }
    }
    const d = new Date(v);
    return isValidDate(d) ? d : null;
  }

  function isWeekend(d)    { const wd = d.getDay(); return wd === 0 || wd === 6; }
  function isHoliday(d)    { return config.HOLIDAYS.includes(d.toISOString().split("T")[0]); }
  function isWorkingDay(d) { return !isWeekend(d) && !isHoliday(d); }

  function subtractWorkingDays(endDate, days) {
    let cur = new Date(endDate);
    let cnt = isWorkingDay(cur) ? 1 : 0;
    while (cnt < days) {
      cur.setDate(cur.getDate() - 1);
      if (isWorkingDay(cur)) cnt++;
    }
    return cur;
  }

  function fmt(d) {
    return {
      day:       String(d.getDate()).padStart(2, "0"),
      month:     config.MONTH_NAMES.genitive[d.getMonth()],
      year:      d.getFullYear(),
      yearShort: String(d.getFullYear()).slice(-2)
    };
  }

  function fmtRussian(d)      { const f = fmt(d); return `«${f.day}» ${f.month} ${f.year} года`; }
  function fmtShortRussian(d) { const f = fmt(d); return `«${f.day}» ${f.month}`; }
  function fmtDDMMYYYY(d)     {
    return `${String(d.getDate()).padStart(2,"0")}.${String(d.getMonth()+1).padStart(2,"0")}.${d.getFullYear()}`;
  }

  function buildResult(startDate, endDate) {
    const s = fmt(startDate);
    const e = fmt(endDate);
    return {
      startDate, endDate,
      startDay: s.day, startMonth: s.month, startYear: s.year, startYearShort: s.yearShort,
      endDay:   e.day, endMonth:   e.month, endYear:   e.year, endYearShort:   e.yearShort,
      startDateFormatted: fmtRussian(startDate),
      endDateFormatted:   fmtRussian(endDate),
      shortEnd:           fmtShortRussian(endDate),
      dateFull:           fmtDDMMYYYY(endDate)
    };
  }

  // Переводим часы → рабочие дни через словарь HOURS_TO_PERIOD
  const days = config.HOURS_TO_PERIOD[String(hours)]?.value || null;

  const startDateVal   = parseDate(regData[C.START_DATE]);
  const endDateVal     = parseDate(regData[C.END_DATE]);
  const issueDateVal   = parseDate(regData[C.ISSUE_DATE]);
  const createdDateVal = parseDate(regData[C.CREATED_DATE]);

  // Вариант 1: фиксированные даты
  if (startDateVal && endDateVal) {
    console.log("    Период: вариант 1 (START_DATE + END_DATE)");
    return buildResult(startDateVal, endDateVal);
  }
  // Вариант 2: дата выдачи + часы
  if (issueDateVal && days) {
    console.log("    Период: вариант 2 (ISSUE_DATE + часы)");
    return buildResult(subtractWorkingDays(issueDateVal, days), issueDateVal);
  }
  // Вариант 3: дата создания + часы
  if (createdDateVal && days) {
    console.log("    Период: вариант 3 (CREATED_DATE + часы)");
    return buildResult(subtractWorkingDays(createdDateVal, days), createdDateVal);
  }
  // Вариант 4: только дата выдачи
  if (issueDateVal) {
    console.log("    Период: вариант 4 (только ISSUE_DATE, −30 дней)");
    const start = new Date(issueDateVal);
    start.setDate(start.getDate() - 30);
    return buildResult(start, issueDateVal);
  }
  // Вариант 5: только дата создания
  if (createdDateVal) {
    console.log("    Период: вариант 5 (только CREATED_DATE, −30 дней)");
    const start = new Date(createdDateVal);
    start.setDate(start.getDate() - 30);
    return buildResult(start, createdDateVal);
  }

  // Fallback
  console.warn("    Период: fallback (нет дат)");
  const end   = new Date();
  const start = new Date();
  start.setDate(end.getDate() - 30);
  return buildResult(start, end);
}

