          }
        }
      };
    }

    // Рег-номера удостоверений из реестра (для remove)
    const existingCertNums = parseRegNumbers(reg[C.REG_NUMBER] || "");

    // Определяем remove, keep и refresh из того что было
    existingVypNums.forEach((regNum, groupKey) => {
      if (currentGroups.has(groupKey)) {
        // Группа осталась — keep + refresh с актуальными данными человека
        const personData = buildPersonVariables(groupKey);
        vypiskaChanges.keep.push({ groupKey, regNumber: regNum });
        if (personData) {
          vypiskaChanges.refresh.push({
            groupKey,
            regNumber: regNum,
            ...personData
          });
        }
      } else {
        const certNumForRemove = existingCertNums.get(groupKey) || "";
        const groupDataForRemove = groupIndex.get(groupKey);
        const periodForRemove = groupDataForRemove ? calculateStudyPeriod(reg, groupDataForRemove.hours): null;
        vypiskaChanges.remove.push({ groupKey, regNumber: regNum, certRegNumber: certNumForRemove,issueDate: periodForRemove ? periodForRemove.dateFull : "" });
      }
    });

    // Определяем add — группы которых не было в выписках раньше
    currentGroups.forEach(groupKey => {
      if (!existingVypNums.has(groupKey)) {
        const personData = buildPersonVariables(groupKey);
        if (!personData) return;

        // Номер удостоверения уже сгенерирован в processGroup и сохранён в generatedCertNums
        // buildPersonVariables его уже подхватил через generatedCertNums.get(groupKey)
        vypiskaChanges.add.push({ groupKey, ...personData });
