          action: isUpdate ? "update" : "create"
        }
      });

      console.log(`  ✅ Удостоверение "${docType}" / группа "${groupKey}" → ${regNumberCert}`);
    }

    // ── ВЫПИСКА (накапливаем людей) ────────────────────────────
    // Ищем шаблон: сначала точный "Выписка {groupKey}",
    // затем универсальный "Выписка"
    const vypískaDocType      = `Выписка ${groupKey}`;
    const vypískaKey          = `${leadLink}|${company}|${groupKey}`;
    const vypískaTemplateLink =
      templateByType.get(vypískaDocType) ||
      templateByType.get("Выписка")      ||
      null;

    if (!vypískaTemplateLink) {
      console.warn(`  ⚠️ Нет шаблона для "${vypískaDocType}" и нет "Выписка" — выписка не будет создана`);
    } else {
      console.log(`  📋 Выписка "${vypískaDocType}" → шаблон найден`);
    }

    if (!vypískaGroups.has(vypískaKey)) {
      vypískaGroups.set(vypískaKey, {
        leadLink,
        company,
        groupKey,
        docType:      vypískaDocType,
        templateLink: vypískaTemplateLink,
        groupData,
        hours,
        folderReg:    reg,   // данные реестра для чтения Рег-номер (Выписка)
        isVypUpdate:  false, // обновляется ниже
        persons: []
      });
    }

    // Выписка считается update если хотя бы одна запись группы имеет папку
    if (isUpdate) {
      vypískaGroups.get(vypískaKey).isVypUpdate = true;
    }

    // person.variables включает рег-номер удостоверения этой группы
    vypískaGroups.get(vypískaKey).persons.push({
      id,
      fio,
      fioDecl,
      variables: { ...variables, [certRegVariable]: regNumberCert }
    });
  }

  otGroups.forEach(groupKey  => processGroup(groupKey, "Удостоверение ОТ"));
  otvGroups.forEach(groupKey => processGroup(groupKey, "Удостоверение ОТВ"));

  // ── АНАЛИЗ ИЗМЕНЕНИЙ В ВЫПИСКАХ ───────────────────────────
  // Только для заявок с существующей папкой
  if (folderLink) {
    // Текущие группы (ОТ + ОТВ) — что должно быть в выписках
    const currentGroups = new Set([...otGroups, ...otvGroups]);

    // Бывшие группы — что уже было сделано (из Рег-номер (Выписка))
    const existingVypNums = parseRegNumbers(reg[C.REG_NUMBER_VYPYSKA] || "");

    const vypiskaChanges = {
      remove:  [], // были раньше, теперь нет → убрать человека из выписки
      add:     [], // новые группы → добавить/создать выписку
      keep:    [], // группа не изменилась (список ключей)
      refresh: []  // группа не изменилась, но данные человека актуализируются
    };

    // Вспомогательная функция — собирает переменные человека для выписки по группе
    function buildPersonVariables(groupKey) {
      const groupData = groupIndex.get(groupKey);
      if (!groupData) return null;

      const hours      = groupData.hours;
      const period     = calculateStudyPeriod(reg, hours);
      const certRegVar = `<<${config.REG_NUMBER_FORMATS["Удостоверение"].variable}>>`;
      const existingCertNums = parseRegNumbers(reg[C.REG_NUMBER] || "");
      const certRegNumber    = existingCertNums.get(groupKey) || "";

      return {
        groupData: {
          groupValue:   groupData.groupValue,
          programValue: groupData.programValue,
          hours
