            "<<Компания>>":              company,
            "<<ИНН>>":                   reg[C.COMPANY_INN]       || "",
            "<<СНИЛС>>":                 reg[C.SNILS]             || "",
            "<<Адрес>>":                 reg[C.ADRESS]            || "",
