            "<<Группа>>":                groupData.groupValue,
            "<<Программа>>":             groupData.programValue,
            "<<Часов>>":                 String(hours),
            "<<Дата>>":                  period.dateFull,
            "<<ОкончаниеОбучения>>":     period.shortEnd,
            "<<от>>":                    period.startDay,
            "<<м-от>>":                  period.startMonth,
            "<<г-от>>":                  String(period.startYear),
            "<<до>>":                    period.endDay,
            "<<м-до>>":                  period.endMonth,
            "<<г-до>>":                  String(period.endYear),
            "<<г-о>>":                   period.startYearShort,
            "<<г-д>>":                   period.endYearShort,
            [certRegVar]:                certRegNumber
          }
        }
      };
    }

    // Определяем remove, keep и refresh из того что было
    existingVypNums.forEach((regNum, groupKey) => {
      if (currentGroups.has(groupKey)) {
        // Группа осталась — keep + refresh с актуальными данными человека
        const personData = buildPersonVariables(groupKey);
        vypiskaChanges.keep.push({ groupKey, regNumber: regNum });
        if (personData) {
          vypiskaChanges.refresh.push({
            groupKey,
            regNumber: regNum,
            ...personData
          });
        }
      } else {
        vypiskaChanges.remove.push({ groupKey, regNumber: regNum });
      }
    });

    // Определяем add — группы которых не было в выписках раньше
    currentGroups.forEach(groupKey => {
      if (!existingVypNums.has(groupKey)) {
        const personData = buildPersonVariables(groupKey);
        if (!personData) return;
        vypiskaChanges.add.push({ groupKey, ...personData });
      }
    });

    const hasChanges =
      vypiskaChanges.remove.length > 0  ||
      vypiskaChanges.add.length > 0     ||
      vypiskaChanges.refresh.length > 0;

    console.log(`  📝 Изменения выписок для ${id}:`);
    if (vypiskaChanges.remove.length)  console.log(`    убрать из:    ${vypiskaChanges.remove.map(x => x.groupKey).join(", ")}`);
    if (vypiskaChanges.add.length)     console.log(`    добавить в:   ${vypiskaChanges.add.map(x => x.groupKey).join(", ")}`);
    if (vypiskaChanges.refresh.length) console.log(`    обновить в:   ${vypiskaChanges.refresh.map(x => x.groupKey).join(", ")}`);

    // Сохраняем в отдельную Map для добавления в пакет
    vypiskaChangesMap.set(id, {
      id,
      fullName,
      leadLink,
      company,
      hasChanges,
      ...vypiskaChanges
    });
  }
});

