//     РАСЧЁТ ПЕРИОДА ОБУЧЕНИЯ
// ===============================================

function calculateStudyPeriod(regData, hours) {
  function isValidDate(d) { return d instanceof Date && !isNaN(d.getTime()); }

  function parseDate(v) {
    if (!v) return null;
    if (typeof v === "string") {
      const m = v.match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
      if (m) {
        const d = new Date(+m[3], +m[2] - 1, +m[1]);
        return isValidDate(d) ? d : null;
      }
    }
    const d = new Date(v);
    return isValidDate(d) ? d : null;
  }

  function isWeekend(d)    { const wd = d.getDay(); return wd === 0 || wd === 6; }
  function isHoliday(d)    { return config.HOLIDAYS.includes(d.toISOString().split("T")[0]); }
  function isWorkingDay(d) { return !isWeekend(d) && !isHoliday(d); }

  function subtractWorkingDays(endDate, days) {
    let cur = new Date(endDate);
    let cnt = isWorkingDay(cur) ? 1 : 0;
    while (cnt < days) {
      cur.setDate(cur.getDate() - 1);
      if (isWorkingDay(cur)) cnt++;
    }
    return cur;
  }

  function fmt(d) {
    return {
      day:       String(d.getDate()).padStart(2, "0"),
      month:     config.MONTH_NAMES.genitive[d.getMonth()],
      year:      d.getFullYear(),
      yearShort: String(d.getFullYear()).slice(-2)
    };
  }

  function fmtRussian(d)      { const f = fmt(d); return `«${f.day}» ${f.month} ${f.year} года`; }
  function fmtShortRussian(d) { const f = fmt(d); return `«${f.day}» ${f.month}`; }
  function fmtDDMMYYYY(d)     {
    return `${String(d.getDate()).padStart(2,"0")}.${String(d.getMonth()+1).padStart(2,"0")}.${d.getFullYear()}`;
  }

  function buildResult(startDate, endDate) {
    const s = fmt(startDate);
    const e = fmt(endDate);
    return {
      startDate, endDate,
      startDay: s.day, startMonth: s.month, startYear: s.year, startYearShort: s.yearShort,
      endDay:   e.day, endMonth:   e.month, endYear:   e.year, endYearShort:   e.yearShort,
      startDateFormatted: fmtRussian(startDate),
      endDateFormatted:   fmtRussian(endDate),
      shortEnd:           fmtShortRussian(endDate),
      dateFull:           fmtDDMMYYYY(endDate)
    };
  }

  // Переводим часы → рабочие дни через словарь HOURS_TO_PERIOD
  const days = config.HOURS_TO_PERIOD[String(hours)]?.value || null;

  const startDateVal   = parseDate(regData[C.START_DATE]);
  const endDateVal     = parseDate(regData[C.END_DATE]);
  const issueDateVal   = parseDate(regData[C.ISSUE_DATE]);
  const createdDateVal = parseDate(regData[C.CREATED_DATE]);

  // Вариант 1: фиксированные даты
  if (startDateVal && endDateVal) {
    console.log("    Период: вариант 1 (START_DATE + END_DATE)");
    return buildResult(startDateVal, endDateVal);
  }
  // Вариант 2: дата выдачи + часы
  if (issueDateVal && days) {
    console.log("    Период: вариант 2 (ISSUE_DATE + часы)");
    return buildResult(subtractWorkingDays(issueDateVal, days), issueDateVal);
  }
  // Вариант 3: дата создания + часы
  if (createdDateVal && days) {
    console.log("    Период: вариант 3 (CREATED_DATE + часы)");
    return buildResult(subtractWorkingDays(createdDateVal, days), createdDateVal);
  }
  // Вариант 4: только дата выдачи
  if (issueDateVal) {
    console.log("    Период: вариант 4 (только ISSUE_DATE, −30 дней)");
    const start = new Date(issueDateVal);
    start.setDate(start.getDate() - 30);
    return buildResult(start, issueDateVal);
  }
  // Вариант 5: только дата создания
  if (createdDateVal) {
    console.log("    Период: вариант 5 (только CREATED_DATE, −30 дней)");
    const start = new Date(createdDateVal);
    start.setDate(start.getDate() - 30);
    return buildResult(start, createdDateVal);
  }

  // Fallback
  console.warn("    Период: fallback (нет дат)");
  const end   = new Date();
  const start = new Date();
  start.setDate(end.getDate() - 30);
  return buildResult(start, end);
}

// ===============================================
//     ОБРАБОТКА РЕЕСТРА
// ===============================================

const certificateTasks = [];

// Выписки: ключ = `${leadLink}|${company}|${groupKey}`
const vypískaGroups = new Map();

// Изменения выписок по заявкам с папкой: ключ = requestId
const vypiskaChangesMap = new Map();

registryRows.forEach(item => {
  const reg = item.json;
  const id  = reg[C.ID];

  if (!id) return;

  const leadLink   = (reg[C.LEAD_LINK]  || "").trim();
  const company    = (reg[C.COMPANY]    || "").trim();
  const fullName   =  reg[C.FULL_NAME]  || "";
  const employee   =  reg[C.EMPLOYEE]   || "";
  const folderLink =  reg[C.FOLDER]     || "";

  const fio     = splitFIO(fullName);
  const fioDecl = splitFIO(reg[C.FULL_NAME_DECLINED] || "");

  const otGroups  = parseGroups(reg[C.OT_GROUP]);
  const otvGroups = parseGroups(reg[C.OTV_GROUP]);

  if (otGroups.length === 0 && otvGroups.length === 0) {
    console.log(`Пропускаем ID=${id}: нет групп ОТ и ОТВ`);
    return;
  }

  console.log(`\n--- Обрабатываем ${id} | ОТ: [${otGroups}] | ОТВ: [${otvGroups}]`);

  function processGroup(groupKey, docType) {
    const groupData = groupIndex.get(groupKey);
    if (!groupData) {
      console.warn(`  ⚠️ Группа "${groupKey}" не найдена в справочнике`);
      return;
    }

    const hours  = groupData.hours;
    const period = calculateStudyPeriod(reg, hours);

    // Базовые переменные
    const variables = {
      "<<ID>>":                    id,
      "<<Фамилия>>":               fio.surname,
      "<<Имя>>":                   fio.name,
      "<<Отчество>>":              fio.patronymic,
      "<<Фамилия в склонении>>":   fioDecl.surname,
      "<<Имя в склонении>>":       fioDecl.name,
      "<<Отчество в склонении>>":  fioDecl.patronymic,
      "<<Должность>>":             reg[C.COMPANY_JOB_TITLE] || "",
      "<<Компания>>":              company,
      "<<ИНН>>":                   reg[C.COMPANY_INN]       || "",
      "<<СНИЛС>>":                 reg[C.SNILS]             || "",
      "<<Адрес>>":                 reg[C.ADRESS]            || "",
      "<<Гражданство>>":           reg[C.CITYZENSHIP]       || "",
      "<<НазваниеМинтруд>>":       reg[C.MINTRUD_NAME]      || "",
      "<<ДатаМинтруд>>":           reg[C.MINTRUD_DATE]      || "",
      "<<НомерМинтруд>>":          reg[C.MITRUD_DOC_NUMBER] || "",
      "<<Группа>>":                groupData.groupValue,
      "<<Программа>>":             groupData.programValue,
      "<<Часов>>":                 String(hours),
      "<<Дата>>":                  period.dateFull,
      "<<ОкончаниеОбучения>>":     period.shortEnd,
      "<<от>>":                    period.startDay,
      "<<м-от>>":                  period.startMonth,
      "<<г-от>>":                  String(period.startYear),
      "<<до>>":                    period.endDay,
      "<<м-до>>":                  period.endMonth,
      "<<г-до>>":                  String(period.endYear),
      "<<г-о>>":                   period.startYearShort,
      "<<г-д>>":                   period.endYearShort,
    };

    // Рег-номер удостоверения:
    // - если папка есть (update) — берём из реестра по ключу группы
    // - если папки нет (create) — генерируем новый
    const certRegVariable  = `<<${config.REG_NUMBER_FORMATS["Удостоверение"].variable}>>`;
    const existingCertNums = parseRegNumbers(reg[C.REG_NUMBER]);
    const isUpdate         = !!folderLink;
    let regNumberCert;
    if (isUpdate) {
      regNumberCert = existingCertNums.get(groupKey) || "";
      console.log(`  🔄 update: рег. номер удостоверения "${groupKey}" из реестра: "${regNumberCert}"`);
    } else {
      regNumberCert = generateRegNumber("ot_counter");
    }

    // ── УДОСТОВЕРЕНИЕ ─────────────────────────────────────────
    const certTemplateLink = templateByType.get(docType);
    if (!certTemplateLink) {
      console.warn(`  ⚠️ Нет шаблона для "${docType}" — удостоверение пропущено`);
    } else {
      certificateTasks.push({
        json: {
          requestId:        id,
          leadLink,
          company,
          employee,
          groupKey,
          documentType:     docType,
          templateId:       certTemplateLink,
          variables:        { ...variables, [certRegVariable]: regNumberCert },
          regNumber:        regNumberCert,
          targetName:       `${id}_${fio.surname}_${docType}_${groupKey}`,
          existingDocument: folderLink || null,
          action: isUpdate ? "update" : "create"
        }
      });

      console.log(`  ✅ Удостоверение "${docType}" / группа "${groupKey}" → ${regNumberCert}`);
    }

    // ── ВЫПИСКА (накапливаем людей) ────────────────────────────
    // Ищем шаблон: сначала точный "Выписка {groupKey}",
    // затем универсальный "Выписка"
    const vypískaDocType      = `Выписка ${groupKey}`;
    const vypískaKey          = `${leadLink}|${company}|${groupKey}`;
    const vypískaTemplateLink =
      templateByType.get(vypískaDocType) ||
      templateByType.get("Выписка")      ||
      null;

    if (!vypískaTemplateLink) {
      console.warn(`  ⚠️ Нет шаблона для "${vypískaDocType}" и нет "Выписка" — выписка не будет создана`);
    } else {
      console.log(`  📋 Выписка "${vypískaDocType}" → шаблон найден`);
    }

    if (!vypískaGroups.has(vypískaKey)) {
      vypískaGroups.set(vypískaKey, {
        leadLink,
        company,
        groupKey,
        docType:      vypískaDocType,
        templateLink: vypískaTemplateLink,
        groupData,
        hours,
        folderReg:    reg,   // данные реестра для чтения Рег-номер (Выписка)
        isVypUpdate:  false, // обновляется ниже
        persons: []
      });
    }

    // Выписка считается update если хотя бы одна запись группы имеет папку
    if (isUpdate) {
      vypískaGroups.get(vypískaKey).isVypUpdate = true;
    }

    // person.variables включает рег-номер удостоверения этой группы
    vypískaGroups.get(vypískaKey).persons.push({
      id,
      fio,
      fioDecl,
      variables: { ...variables, [certRegVariable]: regNumberCert }
    });
  }

  otGroups.forEach(groupKey  => processGroup(groupKey, "Удостоверение ОТ"));
  otvGroups.forEach(groupKey => processGroup(groupKey, "Удостоверение ОТВ"));

  // ── АНАЛИЗ ИЗМЕНЕНИЙ В ВЫПИСКАХ ───────────────────────────
  // Только для заявок с существующей папкой
  if (folderLink) {
    // Текущие группы (ОТ + ОТВ) — что должно быть в выписках
    const currentGroups = new Set([...otGroups, ...otvGroups]);

    // Бывшие группы — что уже было сделано (из Рег-номер (Выписка))
    const existingVypNums = parseRegNumbers(reg[C.REG_NUMBER_VYPYSKA] || "");

    const vypiskaChanges = {
      remove:  [], // были раньше, теперь нет → убрать человека из выписки
      add:     [], // новые группы → добавить/создать выписку
      keep:    [], // группа не изменилась (список ключей)
      refresh: []  // группа не изменилась, но данные человека актуализируются
    };

    // Вспомогательная функция — собирает переменные человека для выписки по группе
    function buildPersonVariables(groupKey) {
      const groupData = groupIndex.get(groupKey);
      if (!groupData) return null;

      const hours      = groupData.hours;
      const period     = calculateStudyPeriod(reg, hours);
      const certRegVar = `<<${config.REG_NUMBER_FORMATS["Удостоверение"].variable}>>`;
      const existingCertNums = parseRegNumbers(reg[C.REG_NUMBER] || "");
      const certRegNumber    = existingCertNums.get(groupKey) || "";

      return {
        groupData: {
          groupValue:   groupData.groupValue,
          programValue: groupData.programValue,
          hours
        },
        person: {
          id,
          fio,
          fioDecl,
          variables: {
            "<<ID>>":                    id,
            "<<Фамилия>>":               fio.surname,
            "<<Имя>>":                   fio.name,
            "<<Отчество>>":              fio.patronymic,
            "<<Фамилия в склонении>>":   fioDecl.surname,
            "<<Имя в склонении>>":       fioDecl.name,
            "<<Отчество в склонении>>":  fioDecl.patronymic,
            "<<Должность>>":             reg[C.COMPANY_JOB_TITLE] || "",
            "<<Компания>>":              company,
            "<<ИНН>>":                   reg[C.COMPANY_INN]       || "",
            "<<СНИЛС>>":                 reg[C.SNILS]             || "",
            "<<Адрес>>":                 reg[C.ADRESS]            || "",
            "<<Гражданство>>":           reg[C.CITYZENSHIP]       || "",
            "<<НазваниеМинтруд>>":       reg[C.MINTRUD_NAME]      || "",
            "<<ДатаМинтруд>>":           reg[C.MINTRUD_DATE]      || "",
            "<<НомерМинтруд>>":          reg[C.MITRUD_DOC_NUMBER] || "",
            "<<Группа>>":                groupData.groupValue,
            "<<Программа>>":             groupData.programValue,
            "<<Часов>>":                 String(hours),
            "<<Дата>>":                  period.dateFull,
            "<<ОкончаниеОбучения>>":     period.shortEnd,
            "<<от>>":                    period.startDay,
            "<<м-от>>":                  period.startMonth,
            "<<г-от>>":                  String(period.startYear),
            "<<до>>":                    period.endDay,
            "<<м-до>>":                  period.endMonth,
            "<<г-до>>":                  String(period.endYear),
            "<<г-о>>":                   period.startYearShort,
            "<<г-д>>":                   period.endYearShort,
            [certRegVar]:                certRegNumber
          }
        }
      };
    }

    // Определяем remove, keep и refresh из того что было
    existingVypNums.forEach((regNum, groupKey) => {
      if (currentGroups.has(groupKey)) {
        // Группа осталась — keep + refresh с актуальными данными человека
        const personData = buildPersonVariables(groupKey);
        vypiskaChanges.keep.push({ groupKey, regNumber: regNum });
        if (personData) {
          vypiskaChanges.refresh.push({
            groupKey,
            regNumber: regNum,
            ...personData
          });
        }
      } else {
        vypiskaChanges.remove.push({ groupKey, regNumber: regNum });
      }
    });

    // Определяем add — группы которых не было в выписках раньше
    currentGroups.forEach(groupKey => {
      if (!existingVypNums.has(groupKey)) {
        const personData = buildPersonVariables(groupKey);
        if (!personData) return;
        vypiskaChanges.add.push({ groupKey, ...personData });
      }
    });

    const hasChanges =
      vypiskaChanges.remove.length > 0  ||
      vypiskaChanges.add.length > 0     ||
      vypiskaChanges.refresh.length > 0;

    console.log(`  📝 Изменения выписок для ${id}:`);
    if (vypiskaChanges.remove.length)  console.log(`    убрать из:    ${vypiskaChanges.remove.map(x => x.groupKey).join(", ")}`);
    if (vypiskaChanges.add.length)     console.log(`    добавить в:   ${vypiskaChanges.add.map(x => x.groupKey).join(", ")}`);
    if (vypiskaChanges.refresh.length) console.log(`    обновить в:   ${vypiskaChanges.refresh.map(x => x.groupKey).join(", ")}`);

    // Сохраняем в отдельную Map для добавления в пакет
    vypiskaChangesMap.set(id, {
      id,
      fullName,
      leadLink,
      company,
      hasChanges,
      ...vypiskaChanges
    });
  }
});

// ===============================================
//     ФОРМИРУЕМ ЗАДАЧИ ДЛЯ ВЫПИСОК
// ===============================================

const vypískaTasksList = [];

vypískaGroups.forEach((group) => {
  const { leadLink, company, groupKey, docType, templateLink, groupData, hours, folderReg, isVypUpdate, persons } = group;

  if (!templateLink) {
    console.warn(`  ⚠️ Выписка "${docType}" — нет шаблона, пропускаем`);
    return;
  }

  // Рег-номер выписки:
  // - если папка есть (update) — берём из реестра по ключу группы
  // - если нет (create) — генерируем новый
  const existingVypNums = parseRegNumbers(folderReg[C.REG_NUMBER_VYPYSKA] || "");
  let regNumberVyp;
  if (isVypUpdate && existingVypNums.has(groupKey)) {
    regNumberVyp = existingVypNums.get(groupKey);
    console.log(`  🔄 update: рег. номер выписки "${groupKey}" из реестра: "${regNumberVyp}"`);
  } else {
    regNumberVyp = generateRegNumber("vypiska_ot_counter");
  }

  // Даты НЕ включаем в общие переменные выписки —
  // у каждого человека своя дата, она уже есть в person.variables
  const vypískaVariables = {
    "<<Группа>>":    groupData.groupValue,
    "<<Программа>>": groupData.programValue,
    "<<Часов>>":     String(hours),
    "<<Компания>>":  company,
    [`<<${config.REG_NUMBER_FORMATS["Выписка"].variable}>>`]: regNumberVyp
  };

  const targetName = `ВЫПИСКА_${groupKey}_${company}`.replace(/[^а-яёА-ЯЁa-zA-Z0-9_\-]/g, "_");

  vypískaTasksList.push({
    json: {
      type:         "vypiska",
      leadLink,
      company,
      groupKey,
      documentType: docType,
      templateId:   templateLink,
      variables:    vypískaVariables,
      persons,
      regNumber:    regNumberVyp,
      targetName,
      action: isVypUpdate ? "update" : "create"
    }
  });

  console.log(`  📋 Выписка "${docType}" | ${company} | ${persons.length} чел. → ${regNumberVyp}`);
});

// ===============================================
//     ГРУППИРОВКА В ПАКЕТЫ ПО LEAD_LINK
// ===============================================

const leadPackets = new Map();

function addToPacket(leadLink, employee, docJson) {
  if (!leadPackets.has(leadLink)) {
    leadPackets.set(leadLink, {
      leadLink,
      employee,
      documents: [],
      summary: { totalDocuments: 0, toCreate: 0, toUpdate: 0 }
    });
  }
  const pkt = leadPackets.get(leadLink);
  if (!pkt.employee && employee) pkt.employee = employee;
  pkt.documents.push(docJson);
  pkt.summary.totalDocuments++;
  if (docJson.action === "create_document") pkt.summary.toCreate++;
  else pkt.summary.toUpdate++;
}

certificateTasks.forEach(t => addToPacket(t.json.leadLink, t.json.employee, t.json));
// Выписки добавляем в documents только для новых заявок (create)
// При update выписки обрабатываются через vypiskaChanges
vypískaTasksList
  .filter(t => t.json.action === "create")
  .forEach(t => addToPacket(t.json.leadLink, "", t.json));

// Собираем изменения выписок по leadLink
const vypiskaChangesByLead = new Map();
vypiskaChangesMap.forEach((changes, id) => {
  const key = changes.leadLink;
  if (!vypiskaChangesByLead.has(key)) vypiskaChangesByLead.set(key, []);
  if (changes.hasChanges) vypiskaChangesByLead.get(key).push(changes);
});

const requestPackets = Array.from(leadPackets.values()).map(pkt => {
  const hasCreate = pkt.documents.some(d => d.action === "create");
  const hasUpdate = pkt.documents.some(d => d.action === "update");
  const action = hasCreate && hasUpdate ? "mixed"
               : hasCreate              ? "create"
               :                          "update";

  return {
    json: {
      action,
      ...pkt,
      vypiskaChanges: vypiskaChangesByLead.get(pkt.leadLink) || [],
      processingType: "batch",
      createdAt: new Date().toISOString()
    }
  };
});

// ===============================================
//     ЗАДАЧА ОБНОВЛЕНИЯ СЧЁТЧИКОВ
// ===============================================

const serviceTasksList = [];

const countersToUpdate = ["ot_counter", "vypiska_ot_counter"]
  .map(name => {
    const counter = countersData.find(c => c.json[CC.COUNTER_TYPE] === name);
    return counter ? { name, value: counter.json[CC.CURRENT_VALUE] } : null;
  })
  .filter(Boolean);

if (countersToUpdate.length > 0) {
  serviceTasksList.push({
    json: { counters_action: "update_counters", counters: countersToUpdate }
  });
}

// ===============================================
//     ИТОГ
// ===============================================

const result = [...requestPackets, ...serviceTasksList];

console.log(`\n=== ИТОГО ===`);
console.log(`Пакетов по лидам:  ${requestPackets.length}`);
console.log(`Удостоверений:     ${certificateTasks.length}`);
console.log(`Выписок:           ${vypískaTasksList.length}`);
console.log(`Служебных задач:   ${serviceTasksList.length}`);
requestPackets.forEach(p => {
  const d = p.json;
  console.log(`  ${d.leadLink}: ${d.summary.totalDocuments} документов (создать: ${d.summary.toCreate}, обновить: ${d.summary.toUpdate})`);
});

return result;

