function findTableStartIndexByHashColumn(doc) {
  const content = doc.body.content;

  for (const block of content) {
    if (!block.table) continue;

    const rows = block.table.tableRows;
    if (!rows || rows.length === 0) continue;

    const firstRow = rows[0];
    if (!firstRow.tableCells || firstRow.tableCells.length === 0) continue;

    const firstCell = firstRow.tableCells[0];
    const cellText = firstCell.content
      ?.flatMap(p => p.paragraph?.elements ?? [])
      ?.map(el => el.textRun?.content ?? "")
      ?.join("")
      ?.trim();

    if (cellText === "№") {
      return [{ tableStartIndex: block.startIndex }];
    }
  }

  return [{ tableStartIndex: null }];
}

return findTableStartIndexByHashColumn($input.first().json);

function buildBatchRequests(doc, values) {
  const content = doc.body.content;

  for (const block of content) {
    if (!block.table) continue;

    const rows = block.table.tableRows;
    if (!rows || rows.length === 0) continue;

    const firstRow = rows[0];
    if (!firstRow.tableCells || firstRow.tableCells.length === 0) continue;

    const firstCell = firstRow.tableCells[0];
    const cellText = firstCell.content
      ?.flatMap(p => p.paragraph?.elements ?? [])
      ?.map(el => el.textRun?.content ?? "")
      ?.join("")
      ?.trim();

    if (cellText !== "№") continue;

    const newRow = rows[1];
    if (!newRow?.tableCells) return [{ requests: null }];

    // Собираем индексы и значения, затем разворачиваем для вставки с конца
    const requests = [...newRow.tableCells]
      .map((cell, i) => ({
        index: cell.content?.[0]?.paragraph?.elements?.[0]?.startIndex ?? null,
        value: values[i] ?? ""
      }))
      .filter(item => item.index !== null && item.value !== "")
      .sort((a, b) => b.index - a.index) // с конца!
      .map(item => ({
        insertText: {
          location: { index: item.index },
          text: item.value
        }
      }));

    return [{ requests }];
  }

  return [{ requests: null }];
}


