const doc = $input.first().json;

const content = doc.body.content;
const table = content
  .find(el => el.table && el.table.columns === 9)?.table;

if (!table) throw new Error("Таблица не найдена");

const updates = [];
for (let i = table.tableRows.length - 1; i >= 1; i--) {
  const cell = table.tableRows[i].tableCells[0];
  const textRun = cell.content[0].paragraph.elements
    .find(el => el.textRun && el.textRun.content !== "\n");

  const newText = String(i);

  if (textRun) {
    updates.push({
      startIndex: textRun.startIndex,
      endIndex: textRun.endIndex - 1, // убираем \n из диапазона
      text: newText,
      hasContent: true
    });
  } else {
    const insertIndex = cell.content[0].paragraph.elements[0].startIndex;
    updates.push({
      startIndex: insertIndex,
      endIndex: null,
      text: newText,
      hasContent: false
    });
  }
}

const requests = updates.flatMap(({ startIndex, endIndex, text, hasContent }) => {
  const ops = [];
  if (hasContent) {
    ops.push({
      deleteContentRange: {
        range: { startIndex, endIndex }
      }
    });
  }
  ops.push({
    insertText: {
      location: { index: startIndex },
      text
    }
  });
  return ops;
});

return [{ json: { requests } }];

