function findRowInDoc(docContent, searchValue) {
  let tableIndex = 0;

  for (const element of docContent) {
    if (!element.table) continue;

    const table = element.table;
    const rows = table.tableRows || [];

    for (let rowIndex = 0; rowIndex < rows.length; rowIndex++) {
      const cells = rows[rowIndex].tableCells || [];

      if (cells.length < 2) continue;

      const secondCell = cells[1];
      let cellText = "";

      for (const contentItem of secondCell.content || []) {
        for (const el of contentItem.paragraph?.elements || []) {
          cellText += el.textRun?.content || "";
        }
      }

      if (cellText.trim() === searchValue.trim()) {
        return {
          found: true,
          tableIndex,
          rowIndex,
          tableStartIndex: element.startIndex // startIndex таблицы в документе
        };
      }
    }

    tableIndex++;
  }

  return { found: false };
}

